arguments.file_text:
#:property AllowUnsafeBlocks=true

Span<nint> a = stackalloc nint[4];
for (int i = 0; i < a.Length; i++)
    a[i] = (nint)(i * 10);

Console.WriteLine($"Span<nint> length: {a.Length}, element size: {nint.Size} bytes");
foreach (var v in a)
    Console.Write($"  {v}");
Console.WriteLine();

Span<nuint> b = stackalloc nuint[3];
b[0] = 42;
b[1] = nuint.MaxValue;
b[2] = 0;

Console.WriteLine($"Span<nuint> length: {b.Length}, max value: {b[1]}");

